#include <omp.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_base_seq(float *a, int size)
{
    int i, j, k;
    float sum;

    for (i = 0; i < size; i++) {
        for (j = i; j < size; j++) {
            sum = a[i * size + j];
            for (k = 0; k < i; k++)
                sum -= a[i * size + k] * a[k * size + j];
            a[i * size + j] = sum;
        }

        for (j = i + 1; j < size; j++) {
            sum = a[j * size + i];
            for (k = 0; k < i; k++)
                sum -= a[j * size + k] * a[k * size + i];
            a[j * size + i] = sum / a[i * size + i];
        }
    }
}

static void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
    int i, j;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[(offset + i) * matrix_dim + offset + j];
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            int k;
            for (k = 0; k < i; k++)
                shadow[j][i] -= shadow[j][k] * shadow[k][i];
            shadow[j][i] /= shadow[i][i];
        }

        for (j = i + 1; j < BLOCK_SIZE; j++) {
            int k;
            for (k = 0; k < i + 1; k++)
                shadow[i + 1][j] -= shadow[i + 1][k] * shadow[k][j];
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + offset + j] = shadow[i][j];
        }
    }
}

static void lud_perimeter_block_omp(float *m, int matrix_dim, int offset, int blk)
{
    int i, j;
    int col_offset = offset + (blk + 1) * BLOCK_SIZE;
    int row_offset = offset + (blk + 1) * BLOCK_SIZE;
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            dia[i][j] = m[(offset + i) * matrix_dim + offset + j];
            peri_row[i][j] = m[(offset + i) * matrix_dim + col_offset + j];
            peri_col[i][j] = m[(row_offset + i) * matrix_dim + offset + j];
        }
    }

    for (j = 0; j < BLOCK_SIZE; j++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            int k;
            for (k = 0; k < i; k++)
                peri_row[i][j] -= dia[i][k] * peri_row[k][j];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            int k;
            for (k = 0; k < j; k++)
                peri_col[i][j] -= peri_col[i][k] * dia[k][j];
            peri_col[i][j] /= dia[j][j];
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + col_offset + j] = peri_row[i][j];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(row_offset + i) * matrix_dim + offset + j] = peri_col[i][j];
        }
    }
}

static void lud_internal_block_omp(float *m, int matrix_dim, int offset, int bx, int by)
{
    int i, j, k;
    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_row[i][j] = m[(offset + i) * matrix_dim + global_col_id + j];
            peri_col[i][j] = m[(global_row_id + i) * matrix_dim + offset + j];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++)
                sum += peri_col[i][k] * peri_row[k][j];
            m[(global_row_id + i) * matrix_dim + global_col_id + j] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int i;

    if (matrix_dim < BLOCK_SIZE || (matrix_dim % BLOCK_SIZE) != 0) {
        lud_base_seq(m, matrix_dim);
        return;
    }

    omp_set_dynamic(0);

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        int blocks = (matrix_dim - i) / BLOCK_SIZE - 1;
        int bx, by;

        lud_diagonal_omp(m, matrix_dim, i);

#pragma omp parallel for private(bx) schedule(static) num_threads(omp_num_threads)
        for (bx = 0; bx < blocks; bx++) {
            lud_perimeter_block_omp(m, matrix_dim, i, bx);
        }

#pragma omp parallel for collapse(2) private(by, bx) schedule(static) num_threads(omp_num_threads)
        for (by = 0; by < blocks; by++) {
            for (bx = 0; bx < blocks; bx++) {
                lud_internal_block_omp(m, matrix_dim, i, bx, by);
            }
        }
    }

    lud_diagonal_omp(m, matrix_dim, i);
}
